                        </button>
                    </div>

                    <div className="mt-8 text-center">
                        <p className="text-xs text-gray-400 leading-relaxed">
                            Protegido por reCAPTCHA e sujeito à Política de Privacidade.<br/>
                            © 2025 GTS - Global Tech Software.
                        </p>
                    </div>
                </form>
            </div>
        </div>
    </div>
  );
};

