import React, { useMemo, useState } from 'react';
import MetricCard from '../components/MetricCard';
import TransactionsTable from '../components/TransactionsTable';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { DollarSignIcon } from '../components/icons/DollarSignIcon';
import { TrendingUpIcon } from '../components/icons/TrendingUpIcon';
import { ArrowUpIcon } from '../components/icons/ArrowUpIcon';
import { ArrowDownIcon } from '../components/icons/ArrowDownIcon';
import { PersonalTransaction, TransactionType, Investment, Page } from '../types';
import WelcomeBanner from '../components/WelcomeBanner';

interface DashboardProps {
    transactions: PersonalTransaction[];
    investments: Investment[];
    setActivePage: (page: Page) => void;
    onEditTransaction: (transaction: PersonalTransaction) => void;
    onDeleteTransaction: (id: string) => void;
    onNewTransaction: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ transactions, investments, setActivePage, onEditTransaction, onDeleteTransaction, onNewTransaction }) => {

  // Estado para o filtro de mês (Padrão: Mês atual no formato YYYY-MM)
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));

  const formatCurrency = (value: number) => {
    return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  }

  // 1. SALDO GLOBAL (Sempre considera todo o histórico - Dinheiro em conta)
  const saldoGlobal = useMemo(() => {
    const receitas = transactions.filter(t => t.type === TransactionType.Receita).reduce((acc, t) => acc + t.amount, 0);
    const despesas = transactions.filter(t => t.type === TransactionType.Despesa).reduce((acc, t) => acc + t.amount, 0);
    return receitas - despesas;
  }, [transactions]);

  // 2. FILTRAR TRANSAÇÕES PELO MÊS SELECIONADO
  const filteredTransactions = useMemo(() => {
      return transactions.filter(t => t.date.startsWith(selectedMonth));
  }, [transactions, selectedMonth]);

  // 3. RECEITAS E DESPESAS (Baseado apenas no mês selecionado - Fluxo de Caixa Mensal)
  const { receitasMensais, despesasMensais } = useMemo(() => {
    const receitas = filteredTransactions.filter(t => t.type === TransactionType.Receita).reduce((acc, t) => acc + t.amount, 0);
    const despesas = filteredTransactions.filter(t => t.type === TransactionType.Despesa).reduce((acc, t) => acc + t.amount, 0);
    return { receitasMensais: receitas, despesasMensais: despesas };
  }, [filteredTransactions]);

  const totalInvestido = useMemo(() => {
      return investments.reduce((acc, inv) => acc + inv.currentValue, 0);
  }, [investments]);

  // Gráfico: Mostra os dados do ANO correspondente ao mês selecionado
  const monthlyChartData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const data = months.map(month => ({ name: month, Receitas: 0, Despesas: 0 }));

    transactions.forEach(transaction => {
      const dateParts = transaction.date.split('-'); // YYYY-MM-DD
      const year = parseInt(dateParts[0]);

      // Filtra o gráfico apenas para o ANO selecionado no filtro
      const selectedYear = parseInt(selectedMonth.split('-')[0]);

      if (year === selectedYear) {
          // Ajuste de fuso horário simples pegando o mês direto da string (01 = Jan, index 0)
          const monthIndex = parseInt(dateParts[1]) - 1; 

          if (monthIndex >= 0 && monthIndex < 12) {
            if (transaction.type === TransactionType.Receita) {
                data[monthIndex].Receitas += transaction.amount;
            } else {
                data[monthIndex].Despesas += transaction.amount;
            }
          }
      }
    });

    return data;
  }, [transactions, selectedMonth]);

  return (
    <div>
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
          <h3 className="text-3xl font-bold text-gray-800">Dashboard Pessoal</h3>

          {/* Componente de Filtro de Mês */}
          <div className="bg-white p-2 rounded-lg shadow-md border border-gray-200 flex items-center">
              <label htmlFor="month-filter" className="mr-2 text-sm font-medium text-gray-600">
                  Período:
              </label>
              <input 
                  type="month" 
                  id="month-filter"
                  value={selectedMonth}
                  onChange={(e) => setSelectedMonth(e.target.value)}
                  className="bg-gray-50 border border-gray-300 text-gray-700 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 p-1.5 outline-none"
              />
          </div>
      </div>

      {transactions.length === 0 ? (
        <WelcomeBanner onActionClick={onNewTransaction} />
      ) : (
        <>
          {/* Metric Cards - Agora são brancos com borda sombreada */}
          <div className="grid gap-6 mb-8 md:grid-cols-2 xl:grid-cols-4">
            <MetricCard
              title="Saldo Atual (Global)"
              value={formatCurrency(saldoGlobal)}
              icon={<DollarSignIcon className="h-8 w-8 text-blue-600" />}
            />
            <MetricCard
              title="Receitas (Mês)"
              value={formatCurrency(receitasMensais)}
              icon={<ArrowUpIcon className="h-8 w-8 text-green-500" />}
              changeType="increase"
            />
            <MetricCard
              title="Despesas (Mês)"
              value={formatCurrency(despesasMensais)}
              icon={<ArrowDownIcon className="h-8 w-8 text-red-500" />}
              changeType="decrease"
            />
            <MetricCard
              title="Total Investido"
              value={formatCurrency(totalInvestido)}
              icon={<TrendingUpIcon className="h-8 w-8 text-indigo-500" />}
            />
          </div>

          {/* Chart - Forçado Branco com Borda e Sombra */}
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
            <div className="xl:col-span-3 bg-white p-8 rounded-2xl shadow-xl border border-gray-200">
                <h4 className="text-xl font-bold text-gray-800 mb-6">
                    Visão Geral de {selectedMonth.split('-')[0]}
                </h4>
                 <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={monthlyChartData}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                        <XAxis dataKey="name" stroke="#6B7280" />
                        <YAxis tickFormatter={(value) => formatCurrency(Number(value))} stroke="#6B7280" />
                        <Tooltip 
                            formatter={(value: number) => formatCurrency(value)}
                            contentStyle={{
                                backgroundColor: '#fff', 
                                border: '1px solid #e5e7eb', 
                                borderRadius: '0.5rem',
                                boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                            }}
                            labelStyle={{color: '#374151', fontWeight: 'bold'}}
                        />
                        <Legend />
                        <Bar dataKey="Receitas" fill="#22C55E" name="Receitas" radius={[4, 4, 0, 0]} />
                        <Bar dataKey="Despesas" fill="#EF4444" name="Despesas" radius={[4, 4, 0, 0]} />
                    </BarChart>
                </ResponsiveContainer>
            </div>
          </div>

          <div className="mt-8">
            {/* Tabela - Forçada Branca com Borda e Sombra */}
            <div className="rounded-2xl shadow-xl bg-white border border-gray-200 overflow-hidden">
                <TransactionsTable 
                    transactions={filteredTransactions} 
                    title={`Transações de ${new Date(selectedMonth + '-02').toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}`}
                    showViewAllLink={true}
                    onViewAll={() => setActivePage('Transações')}
                    onEdit={onEditTransaction}
                    onDelete={onDeleteTransaction}
                />
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { PersonalTransaction, TransactionType } from '../types';
import { MoreVerticalIcon } from './icons/MoreVerticalIcon';
import { EditIcon } from './icons/EditIcon';
import { TrashIcon } from './icons/TrashIcon';

interface TransactionsTableProps {
  transactions: PersonalTransaction[];
  title?: string;
  onEdit?: (transaction: PersonalTransaction) => void;
  onDelete?: (id: string) => void;
  onViewAll?: () => void;
  showViewAllLink?: boolean;
}

const ActionMenu: React.FC<{ transaction: PersonalTransaction; onEdit: any; onDelete: any; }> = ({ transaction, onEdit, onDelete }) => {
    const [isOpen, setIsOpen] = React.useState(false);
    const menuRef = React.useRef<HTMLDivElement>(null);

    React.useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    return (
        <div className="relative" ref={menuRef}>
            <button onClick={() => setIsOpen(!isOpen)} className="text-gray-500 hover:text-gray-800 p-2 rounded-full hover:bg-gray-100 transition-colors">
                <MoreVerticalIcon className="h-5 w-5" />
            </button>
            {isOpen && (
                <div className="absolute right-0 mt-2 w-32 bg-white rounded-md shadow-lg py-1 z-10 border border-gray-200">
                    <button onClick={() => { onEdit(transaction); setIsOpen(false); }} className="w-full text-left flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-100">
                        <EditIcon className="h-4 w-4 mr-2" /> Editar
                    </button>
                    <button onClick={() => { onDelete(transaction.id); setIsOpen(false); }} className="w-full text-left flex items-center px-4 py-2 text-sm text-red-600 hover:bg-red-50">
                        <TrashIcon className="h-4 w-4 mr-2" /> Excluir
                    </button>
                </div>
            )}
        </div>
    );
};

const TransactionsTable: React.FC<TransactionsTableProps> = ({ 
    transactions, 
    title = "Transações",
    onEdit,
    onDelete,
    onViewAll,
    showViewAllLink = false,
}) => {
  return (
    <div className="bg-white rounded-xl shadow-none"> {/* Shadow removida aqui pois o container pai já tem */}
      <div className="p-6 border-b border-gray-100">
        <h4 className="text-xl font-bold text-gray-800">{title}</h4>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left text-gray-500">
          <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-100">
            <tr>
              <th scope="col" className="px-6 py-4 font-bold">Descrição</th>
              <th scope="col" className="px-6 py-4 font-bold">Valor</th>
              <th scope="col" className="px-6 py-4 font-bold">Data</th>
              <th scope="col" className="px-6 py-4 font-bold">Categoria</th>
              <th scope="col" className="px-6 py-4 font-bold">Tipo</th>
              <th scope="col" className="px-6 py-4 font-bold"><span className="sr-only">Ações</span></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {transactions.map((transaction) => (
              <tr key={transaction.id} className="bg-white hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 font-semibold text-gray-900">
                    {transaction.description}
                </td>
                <td className={`px-6 py-4 font-bold ${transaction.type === TransactionType.Receita ? 'text-green-600' : 'text-red-600'}`}>
                  {transaction.type === TransactionType.Despesa && '- '}
                  R$ {transaction.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="px-6 py-4">
                  {new Date(transaction.date).toLocaleDateString('pt-BR', {timeZone: 'UTC'})}
                </td>
                <td className="px-6 py-4">
                  <span className="bg-gray-100 text-gray-700 text-xs font-bold px-2.5 py-1 rounded-full border border-gray-200">
                    {transaction.category}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <TypeBadge type={transaction.type} />
                </td>
                <td className="px-6 py-4 text-right">
                   {onEdit && onDelete && <ActionMenu transaction={transaction} onEdit={onEdit} onDelete={onDelete} />}
                </td>
              </tr>
            ))}
             {transactions.length === 0 && (
                <tr>
                    <td colSpan={6} className="text-center py-8 text-gray-500">Nenhuma transação encontrada.</td>
                </tr>
            )}
          </tbody>
        </table>
      </div>
      {showViewAllLink && onViewAll && (
        <div className="p-4 text-center border-t border-gray-100">
            <button onClick={onViewAll} className="text-sm font-bold text-blue-600 hover:text-blue-800 transition-colors">Ver todas as transações</button>
        </div>
      )}
    </div>
  );
};


const TypeBadge: React.FC<{ type: TransactionType }> = ({ type }) => {
  const baseClasses = 'px-3 py-1 text-xs font-bold rounded-full inline-block border';
  let typeClasses = '';

  switch (type) {
    case TransactionType.Receita:
      typeClasses = 'bg-green-50 text-green-700 border-green-200';
      break;
    case TransactionType.Despesa:
      typeClasses = 'bg-red-50 text-red-700 border-red-200';
      break;
  }

  return <span className={`${baseClasses} ${typeClasses}`}>{type}</span>;
};


