import React, { useState } from 'react';
import { AgendaTask } from '../types';
import { PlusIcon } from '../components/icons/PlusIcon';
import { TrashIcon } from '../components/icons/TrashIcon';
import { CheckCircleIcon } from '../components/icons/CheckCircleIcon';
import { XIcon } from '../components/icons/XIcon';

interface AgendaProps {
    tasks: AgendaTask[];
    onAddTask: (task: Omit<AgendaTask, 'id'>) => void;
    onToggleTask: (id: string, done: boolean) => void;
    onDeleteTask: (id: string) => void;
}

const Agenda: React.FC<AgendaProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newTaskDesc, setNewTaskDesc] = useState('');
    const [newTaskDate, setNewTaskDate] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (newTaskDesc && newTaskDate) {
            onAddTask({
                description: newTaskDesc,
                date: newTaskDate,
                done: false
            });
            setNewTaskDesc('');
            setNewTaskDate('');
            setIsModalOpen(false);
        }
    };

    // Agrupar tarefas por data e ordenar cronologicamente
    const sortedTasks = [...tasks].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-3xl font-bold text-gray-800">Minha Agenda</h3>
                <button 
                    onClick={() => {
                        setNewTaskDate(new Date().toISOString().split('T')[0]);
                        setIsModalOpen(true);
                    }} 
                    className="flex items-center justify-center bg-blue-600 text-white px-5 py-2.5 rounded-full hover:bg-blue-700 transition-colors duration-200 text-sm font-bold shadow-md hover:shadow-lg"
                >
                    <PlusIcon className="h-5 w-5 mr-2" />
                    Adicionar Lembrete
                </button>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-200">
                {sortedTasks.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <p className="text-lg">Você não tem lembretes agendados.</p>
                        <p className="text-sm mt-2">Clique em "Adicionar Lembrete" para começar.</p>
                    </div>
                ) : (
                    <ul className="space-y-4">
                        {sortedTasks.map((task) => {
                             const isPast = new Date(task.date) < new Date(new Date().setHours(0,0,0,0));
                             const isToday = new Date(task.date).toISOString().split('T')[0] === new Date().toISOString().split('T')[0];

                             return (
                                <li key={task.id} className={`flex items-center justify-between p-4 rounded-xl border transition-all ${task.done ? 'bg-gray-50 border-gray-100 opacity-75' : 'bg-white border-gray-200 hover:border-blue-300 hover:shadow-md'}`}>
                                    <div className="flex items-center space-x-4">
                                        <button 
                                            onClick={() => onToggleTask(task.id, !task.done)}
                                            className={`p-2 rounded-full transition-colors ${task.done ? 'text-green-500 bg-green-50' : 'text-gray-300 hover:text-blue-500 hover:bg-blue-50'}`}
                                        >
                                            <CheckCircleIcon className="h-6 w-6" />
                                        </button>
                                        <div>
                                            <p className={`font-bold text-gray-800 ${task.done ? 'line-through text-gray-500' : ''}`}>
                                                {task.description}
                                            </p>
                                            <div className="flex items-center text-sm mt-1">
                                                <span className={`px-2 py-0.5 rounded text-xs font-semibold mr-2 ${isPast && !task.done ? 'bg-red-100 text-red-700' : isToday ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-600'}`}>
                                                    {isPast && !task.done ? 'Atrasado' : isToday ? 'Hoje' : 'Futuro'}
                                                </span>
                                                <span className="text-gray-500">
                                                    {new Date(task.date).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={() => onDeleteTask(task.id)}
                                        className="p-2 text-gray-400 hover:text-red-600 rounded-full hover:bg-red-50 transition-colors"
                                    >
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </li>
                            );
                        })}
                    </ul>
                )}
            </div>

            {/* Modal de Adição */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-md m-4 p-6">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-xl font-bold text-gray-800">Novo Lembrete</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <XIcon className="h-6 w-6" />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">O que você precisa fazer?</label>
                                <input 
                                    type="text" 
                                    value={newTaskDesc}
                                    onChange={(e) => setNewTaskDesc(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    placeholder="Ex: Pagar conta de luz"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Quando?</label>
                                <input 
                                    type="date" 
                                    value={newTaskDate}
                                    onChange={(e) => setNewTaskDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    required
                                />
                            </div>
                            <div className="flex justify-end pt-4">
                                <button type="submit" className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-blue-700 transition-colors">
                                    Adicionar
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Agenda;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import Transactions from './pages/Transactions';
import Investments from './pages/Investments';
import Agenda from './pages/Agenda';
import Settings from './pages/Settings';
import LoginPage from './pages/LoginPage';
import TransactionModal from './components/TransactionModal';
import { MenuIcon } from './components/icons/MenuIcon';
import { PersonalTransaction, Investment, User, Page, Theme, AgendaTask } from './types';
import { api } from './services/api';
import WhatsAppButton from './components/WhatsAppButton';

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activePage, setActivePage] = useState<Page>('Dashboard');

  const [transactions, setTransactions] = useState<PersonalTransaction[]>([]);
  const [investments, setInvestments] = useState<Investment[]>([]);
  const [tasks, setTasks] = useState<AgendaTask[]>([]);
  const [theme, setTheme] = useState<Theme>(() => (localStorage.getItem('theme') as Theme) || 'light');

  // Estado para busca global
  const [searchQuery, setSearchQuery] = useState('');

  // Load user and token from localStorage if available to persist session on refresh
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
      const savedUser = localStorage.getItem('user_data');
      return savedUser ? JSON.parse(savedUser) : null;
  });
  const [token, setToken] = useState<string | null>(localStorage.getItem('auth_token'));

  const [cdiRate, setCdiRate] = useState(0);

  const [isTransactionModalOpen, setIsTransactionModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<PersonalTransaction | null>(null);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if (token) {
        const fetchData = async () => {
             // 1. Atualiza Transações
             const txs = await api.getTransactions(token);
             if (Array.isArray(txs)) setTransactions(txs);

             // 2. Atualiza Investimentos
             const invs = await api.getInvestments(token);
             if (Array.isArray(invs)) setInvestments(invs);

             // 3. Atualiza Agenda
             const userTasks = await api.getTasks(token);
             if (Array.isArray(userTasks)) setTasks(userTasks);

             // 4. ATUALIZA DADOS DO PERFIL (Para garantir que Foto, CPF, Tel e Status estejam sincronizados)
             const userProfile = await api.getMe(token);
             if (userProfile && !userProfile.error) {
                 setCurrentUser(userProfile);
                 localStorage.setItem('user_data', JSON.stringify(userProfile));
             }
        };
        fetchData();
    }
  }, [token]);

  const handleLogin = (user: User, authToken: string) => {
    setCurrentUser(user);
    setToken(authToken);
    localStorage.setItem('user_data', JSON.stringify(user));
    localStorage.setItem('auth_token', authToken);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setToken(null);
    localStorage.removeItem('user_data');
    localStorage.removeItem('auth_token');
    setTransactions([]);
    setInvestments([]);
    setTasks([]);
  };

  const handleSaveTransaction = async (transaction: Omit<PersonalTransaction, 'id'> & { id?: string }) => {
    if (!token) return;

    if (transaction.id) {
         const txId = transaction.id;
         setTransactions(prev => prev.map(t => t.id === txId ? { ...transaction, id: txId } as PersonalTransaction : t));
    } else {
        await api.createTransaction(transaction, token);
        const txs = await api.getTransactions(token);
        if (Array.isArray(txs)) setTransactions(txs);
    }
    setIsTransactionModalOpen(false);
    setEditingTransaction(null);
  };

  const handleDeleteTransaction = async (id: string) => {
     if (!token) return;
     if (window.confirm("Tem certeza que deseja excluir esta transação permanentemente?")) {
         // Atualiza UI otimista
         setTransactions(prev => prev.filter(t => t.id !== id));

         // Chama API
         const result = await api.deleteTransaction(id, token);
         if (result.error) {
             alert(result.message);
             // Reverte se der erro (opcional, aqui estamos apenas recarregando)
             const txs = await api.getTransactions(token);
             if (Array.isArray(txs)) setTransactions(txs);
         }
     }
  };

  const handleSaveInvestment = async (investment: Omit<Investment, 'id'> & { id?: string }) => {
      if (!token) return;
      if (investment.id) {
          const invId = investment.id;
          setInvestments(prev => prev.map(i => i.id === invId ? { ...investment, id: invId } as Investment : i));
      } else {
          await api.createInvestment(investment, token);
          const invs = await api.getInvestments(token);
          if (Array.isArray(invs)) setInvestments(invs);
      }
  };

  const handleDeleteInvestment = async (id: string) => {
      if (!token) return;
      if (window.confirm("Tem certeza que deseja excluir este investimento permanentemente?")) {
          setInvestments(prev => prev.filter(i => i.id !== id));

          const result = await api.deleteInvestment(id, token);
          if (result.error) {
              alert(result.message);
              const invs = await api.getInvestments(token);
              if (Array.isArray(invs)) setInvestments(invs);
          }
      }
  }

  // --- AGENDA HANDLERS ---
  const handleAddTask = async (task: Omit<AgendaTask, 'id'>) => {
      if (!token) return;
      // Optimistic update
      const tempId = 'temp-' + Date.now();
      setTasks(prev => [...prev, { ...task, id: tempId }]);

      const response = await api.createTask(task, token);
      if (!response.error) {
          const serverTasks = await api.getTasks(token);
          if(Array.isArray(serverTasks)) setTasks(serverTasks);
      }
  };

  const handleToggleTask = async (id: string, done: boolean) => {
      if (!token) return;
      setTasks(prev => prev.map(t => t.id === id ? { ...t, done } : t));
      await api.toggleTask(id, done, token);
  };

  const handleDeleteTask = async (id: string) => {
      if (!token) return;
      if (window.confirm("Excluir lembrete?")) {
        setTasks(prev => prev.filter(t => t.id !== id));
        await api.deleteTask(id, token);
      }
  };

  const handleUpdatePassword = async (current: string, newPass: string) => {
      if(token) await api.updatePassword({currentPassword: current, newPassword: newPass}, token);
      alert("Senha atualizada (se as credenciais estavam corretas).");
  };

  const handleUpdateAvatar = async (avatar: string) => {
      if (token) {
          await api.updateAvatar({avatar}, token);
          if (currentUser) {
              const updatedUser = { ...currentUser, avatar };
              setCurrentUser(updatedUser);
              localStorage.setItem('user_data', JSON.stringify(updatedUser));
          }
      }
  };

  const handleCreateUser = async (newUser: Omit<User, 'id'>) => {
     return await api.createUser(newUser);
  };

  if (!token) {
      return (
          <>
            <LoginPage onLogin={handleLogin} />
            <WhatsAppButton />
          </>
      );
  }

  return (
    // Sidebar Escura (#020617) + Conteúdo Claro (bg-slate-50)
    <div className="flex h-screen bg-slate-50 font-sans">
       {isSidebarOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black opacity-50 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        ></div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <div className="flex-1 flex flex-col overflow-hidden bg-slate-50">
        <Header 
            onLogout={handleLogout} 
            onNewTransaction={() => {
                setEditingTransaction(null);
                setIsTransactionModalOpen(true);
            }}
            currentUser={currentUser}
            setActivePage={setActivePage}
            onSearch={setSearchQuery}
        >
             <button
              className="md:hidden mr-4 text-gray-500 focus:outline-none"
              onClick={() => setIsSidebarOpen(true)}
            >
              <MenuIcon className="h-6 w-6" />
            </button>
        </Header>

        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-slate-50 p-4 md:p-8 relative">
            {activePage === 'Dashboard' && (
                <Dashboard 
                    transactions={transactions} 
                    investments={investments}
                    setActivePage={setActivePage}
                    onEditTransaction={(t) => {
                        setEditingTransaction(t);
                        setIsTransactionModalOpen(true);
                    }}
                    onDeleteTransaction={handleDeleteTransaction}
                    onNewTransaction={() => {
                        setEditingTransaction(null);
                        setIsTransactionModalOpen(true);
                    }}
                    searchQuery={searchQuery}
                />
            )}
            {activePage === 'Transações' && (
                <Transactions 
                    transactions={transactions}
                    onOpenModal={(t) => {
                        setEditingTransaction(t);
                        setIsTransactionModalOpen(true);
                    }}
                    onDeleteTransaction={handleDeleteTransaction}
                    searchQuery={searchQuery}
                />
            )}
            {activePage === 'Agenda' && (
                <Agenda 
                    tasks={tasks}
                    onAddTask={handleAddTask}
                    onToggleTask={handleToggleTask}
                    onDeleteTask={handleDeleteTask}
                />
            )}
            {activePage === 'Investimentos' && (
                <Investments 
                    investments={investments}
                    setInvestments={setInvestments}
                    cdiRate={cdiRate}
                    onSaveInvestment={handleSaveInvestment}
                    onDeleteInvestment={handleDeleteInvestment}
                />
            )}
            {activePage === 'Configurações' && currentUser && (
                <Settings 
                    theme={theme} 
                    setTheme={setTheme}
                    currentUser={currentUser}
                    onUpdatePassword={handleUpdatePassword}
                    onUpdateAvatar={handleUpdateAvatar}
                    onCreateUser={handleCreateUser}
                />
            )}
        </main>
      </div>

      <TransactionModal
        isOpen={isTransactionModalOpen}
        onClose={() => setIsTransactionModalOpen(false)}
        onSave={handleSaveTransaction}
        transaction={editingTransaction}
      />

      {/* Floating WhatsApp Button */}
      <WhatsAppButton />
    </div>
  );
};

export default App;

