import React, { useState } from 'react';
import { CalendarEvent } from '../types';
import { PlusIcon } from '../components/icons/PlusIcon';
import { TrashIcon } from '../components/icons/TrashIcon';
import { CheckCircleIcon } from '../components/icons/CheckCircleIcon';
import { XIcon } from '../components/icons/XIcon';

interface AgendaProps {
    tasks: CalendarEvent[];
    onAddTask: (task: Omit<CalendarEvent, 'id'>) => void;
    onToggleTask: (id: string, done: boolean) => void;
    onDeleteTask: (id: string) => void;
}

const Agenda: React.FC<AgendaProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newTaskDesc, setNewTaskDesc] = useState('');
    const [newTaskDate, setNewTaskDate] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (newTaskDesc && newTaskDate) {
            onAddTask({
                description: newTaskDesc,
                date: newTaskDate,
                done: false
            });
            setNewTaskDesc('');
            setNewTaskDate('');
            setIsModalOpen(false);
        }
    };

    // Agrupar tarefas por data e ordenar cronologicamente
    const sortedTasks = [...tasks].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-3xl font-bold text-gray-800">Minha Agenda</h3>
                <button 
                    onClick={() => {
                        setNewTaskDate(new Date().toISOString().split('T')[0]);
                        setIsModalOpen(true);
                    }} 
                    className="flex items-center justify-center bg-blue-600 text-white px-5 py-2.5 rounded-full hover:bg-blue-700 transition-colors duration-200 text-sm font-bold shadow-md hover:shadow-lg"
                >
                    <PlusIcon className="h-5 w-5 mr-2" />
                    Adicionar Lembrete
                </button>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-200">
                {sortedTasks.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <p className="text-lg">Você não tem lembretes agendados.</p>
                        <p className="text-sm mt-2">Clique em "Adicionar Lembrete" para começar.</p>
                    </div>
                ) : (
                    <ul className="space-y-4">
                        {sortedTasks.map((task) => {
                             const isPast = new Date(task.date) < new Date(new Date().setHours(0,0,0,0));
                             const isToday = new Date(task.date).toISOString().split('T')[0] === new Date().toISOString().split('T')[0];

                             return (
                                <li key={task.id} className={`flex items-center justify-between p-4 rounded-xl border transition-all ${task.done ? 'bg-gray-50 border-gray-100 opacity-75' : 'bg-white border-gray-200 hover:border-blue-300 hover:shadow-md'}`}>
                                    <div className="flex items-center space-x-4">
                                        <button 
                                            onClick={() => onToggleTask(task.id, !task.done)}
                                            className={`p-2 rounded-full transition-colors ${task.done ? 'text-green-500 bg-green-50' : 'text-gray-300 hover:text-blue-500 hover:bg-blue-50'}`}
                                        >
                                            <CheckCircleIcon className="h-6 w-6" />
                                        </button>
                                        <div>
                                            <p className={`font-bold text-gray-800 ${task.done ? 'line-through text-gray-500' : ''}`}>
                                                {task.description}
                                            </p>
                                            <div className="flex items-center text-sm mt-1">
                                                <span className={`px-2 py-0.5 rounded text-xs font-semibold mr-2 ${isPast && !task.done ? 'bg-red-100 text-red-700' : isToday ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-600'}`}>
                                                    {isPast && !task.done ? 'Atrasado' : isToday ? 'Hoje' : 'Futuro'}
                                                </span>
                                                <span className="text-gray-500">
                                                    {new Date(task.date).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={() => onDeleteTask(task.id)}
                                        className="p-2 text-gray-400 hover:text-red-600 rounded-full hover:bg-red-50 transition-colors"
                                    >
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </li>
                            );
                        })}
                    </ul>
                )}
            </div>

            {/* Modal de Adição */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-md m-4 p-6">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-xl font-bold text-gray-800">Novo Lembrete</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <XIcon className="h-6 w-6" />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">O que você precisa fazer?</label>
                                <input 
                                    type="text" 
                                    value={newTaskDesc}
                                    onChange={(e) => setNewTaskDesc(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    placeholder="Ex: Pagar conta de luz"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Quando?</label>
                                <input 
                                    type="date" 
                                    value={newTaskDate}
                                    onChange={(e) => setNewTaskDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    required
                                />
                            </div>
                            <div className="flex justify-end pt-4">
                                <button type="submit" className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-blue-700 transition-colors">
                                    Adicionar
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

