  const handleCreateUser = async (newUser: Omit<User, 'id'>) => {
     return await api.createUser(newUser);
  };

  if (!token) {
      return (
          <>
            <LoginPage onLogin={handleLogin} />
            <WhatsAppButton />
          </>
      );
