                    transactions={transactions} 
                    investments={investments}
                    setActivePage={setActivePage}
                    onEditTransaction={(t) => {
                        setEditingTransaction(t);
                        setIsTransactionModalOpen(true);
                    }}
                    onDeleteTransaction={handleDeleteTransaction}
                    onNewTransaction={() => {
                        setEditingTransaction(null);
                        setIsTransactionModalOpen(true);
                    }}
