                </button>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-200">
                {sortedTasks.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <CalendarIcon className="h-12 w-12 mx-auto text-gray-300 mb-3" />
