  return investments;
}

function createInvestment(body, userEmail) {
  const sheet = getSpreadsheet().getSheetByName('Investments');
  if (!sheet) throw new Error("Aba 'Investments' não encontrada.");

  const newId = "INV" + new Date().getTime();

  sheet.appendRow([
