  // Load user and token from localStorage if available to persist session on refresh
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
      const savedUser = localStorage.getItem('user_data');
      return savedUser ? JSON.parse(savedUser) : null;
  });
  const [token, setToken] = useState<string | null>(localStorage.getItem('auth_token'));

  const [cdiRate, setCdiRate] = useState(0);

  const [isTransactionModalOpen, setIsTransactionModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<PersonalTransaction | null>(null);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    if (token) {
        const fetchData = async () => {
             // 1. Atualiza Transações
             const txs = await api.getTransactions(token);
             if (Array.isArray(txs)) setTransactions(txs);

             // 2. Atualiza Investimentos
             const invs = await api.getInvestments(token);
             if (Array.isArray(invs)) setInvestments(invs);

             // 3. Atualiza Agenda (CALENDAR)
             const userTasks = await api.getCalendarEvents(token);
             if (Array.isArray(userTasks)) setTasks(userTasks);

             // 4. ATUALIZA DADOS DO PERFIL (Para garantir que Foto, CPF, Tel e Status estejam sincronizados)
             const userProfile = await api.getMe(token);
             if (userProfile && !userProfile.error) {
                 setCurrentUser(userProfile);
                 localStorage.setItem('user_data', JSON.stringify(userProfile));
             }
        };
        fetchData();
    }
  }, [token]);

  const showToast = (message: string, type: 'success' | 'error' | 'info') => {
      setToast({ id: Date.now().toString(), message, type });
  };

  const handleLogin = (user: User, authToken: string) => {
    setCurrentUser(user);
    setToken(authToken);
    localStorage.setItem('user_data', JSON.stringify(user));
    localStorage.setItem('auth_token', authToken);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setToken(null);
    localStorage.removeItem('user_data');
    localStorage.removeItem('auth_token');
    setTransactions([]);
    setInvestments([]);
    setTasks([]);
  };

  const handleSaveTransaction = async (transaction: Omit<PersonalTransaction, 'id'> & { id?: string }) => {
    if (!token) return;

    if (transaction.id) {
         const txId = transaction.id;
         setTransactions(prev => prev.map(t => t.id === txId ? { ...transaction, id: txId } as PersonalTransaction : t));
         showToast("Transação atualizada!", "success");
    } else {
        await api.createTransaction(transaction, token);
        const txs = await api.getTransactions(token);
        if (Array.isArray(txs)) setTransactions(txs);
        showToast("Transação criada com sucesso!", "success");
    }
    setIsTransactionModalOpen(false);
    setEditingTransaction(null);
  };

  const handleDeleteTransaction = async (id: string) => {
     if (!token) return;
     if (window.confirm("Tem certeza que deseja excluir esta transação permanentemente?")) {
         // Atualiza UI otimista
         setTransactions(prev => prev.filter(t => t.id !== id));
         showToast("Transação removida.", "error");

         // Chama API
         const result = await api.deleteTransaction(id, token);
         if (result.error) {
             alert(result.message);
             // Reverte se der erro (opcional, aqui estamos apenas recarregando)
             const txs = await api.getTransactions(token);
             if (Array.isArray(txs)) setTransactions(txs);
         }
     }
  };

  const handleSaveInvestment = async (investment: Omit<Investment, 'id'> & { id?: string }) => {
      if (!token) return;
      if (investment.id) {
          const invId = investment.id;
          setInvestments(prev => prev.map(i => i.id === invId ? { ...investment, id: invId } as Investment : i));
          showToast("Investimento atualizado!", "success");
      } else {
          await api.createInvestment(investment, token);
          const invs = await api.getInvestments(token);
          if (Array.isArray(invs)) setInvestments(invs);
          showToast("Investimento adicionado!", "success");
      }
  };

  const handleDeleteInvestment = async (id: string) => {
      if (!token) return;
      if (window.confirm("Tem certeza que deseja excluir este investimento permanentemente?")) {
          setInvestments(prev => prev.filter(i => i.id !== id));
          showToast("Investimento removido.", "error");

          const result = await api.deleteInvestment(id, token);
          if (result.error) {
              alert(result.message);
              const invs = await api.getInvestments(token);
              if (Array.isArray(invs)) setInvestments(invs);
          }
      }
  }

  // --- AGENDA HANDLERS (CALENDAR) ---
  const handleAddTask = async (task: Omit<CalendarEvent, 'id'>) => {
      if (!token) return;
      // 1. Cria ID temporário para mostrar na tela imediatamente
      const tempId = 'temp-' + Date.now();
      const tempTask = { ...task, id: tempId };

      // 2. Atualiza UI (Otimista)
      setTasks(prev => [...prev, tempTask]);
      showToast("Lembrete adicionado à agenda!", "success");

      // 3. Chama o servidor
      const response = await api.createCalendarEvent(task, token);

      if (response && response.id) {
          // 4. SUCESSO: Troca o ID temporário pelo ID real do banco
          setTasks(prev => prev.map(t => t.id === tempId ? { ...t, id: response.id } : t));
      } else {
          // 5. FALHA ou Fallback: Recarrega tudo se algo der errado
          const serverTasks = await api.getCalendarEvents(token);
          if(Array.isArray(serverTasks)) setTasks(serverTasks);
      }
  };

  const handleToggleTask = async (id: string, done: boolean) => {
      if (!token) return;
      // Atualiza UI Imediatamente
      setTasks(prev => prev.map(t => t.id === id ? { ...t, done } : t));

      // Notificação Visual
      if (done) {
          showToast("Tarefa concluída! 🎉", "success");
      } else {
          showToast("Tarefa reaberta.", "info");
      }

      await api.toggleCalendarEvent(id, done, token);
  };

  const handleDeleteTask = async (id: string) => {
      if (!token) return;
      if (window.confirm("Excluir lembrete?")) {
        // Atualiza UI Imediatamente (Remove o item)
        setTasks(prev => prev.filter(t => t.id !== id));
        showToast("Lembrete excluído.", "error");

        // Chama API para deletar
        await api.deleteCalendarEvent(id, token);
      }
  };

  const handleUpdatePassword = async (current: string, newPass: string) => {
      if(token) await api.updatePassword({currentPassword: current, newPassword: newPass}, token);
      showToast("Senha atualizada com sucesso.", "success");
  };

  const handleUpdateAvatar = async (avatar: string) => {
      if (token) {
          await api.updateAvatar({avatar}, token);
          if (currentUser) {
              const updatedUser = { ...currentUser, avatar };
              setCurrentUser(updatedUser);
              localStorage.setItem('user_data', JSON.stringify(updatedUser));
              showToast("Foto de perfil atualizada!", "success");
          }
      }
  };

  const handleCreateUser = async (newUser: Omit<User, 'id'>) => {
     return await api.createUser(newUser);
  };

  if (!token) {
      return (
          <>
            <LoginPage onLogin={handleLogin} />
            <WhatsAppButton />
          </>
      );
  }

  return (
    // Sidebar Escura (#020617) + Conteúdo Claro (bg-slate-50)
    <div className="flex h-screen bg-slate-50 font-sans relative">
       {/* Sistema de Notificação (Toast) */}
       {toast && <Toast toast={toast} onClose={() => setToast(null)} />}

       {isSidebarOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black opacity-50 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        ></div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <div className="flex-1 flex flex-col overflow-hidden bg-slate-50">
        <Header 
            onLogout={handleLogout} 
            onNewTransaction={() => {
                setEditingTransaction(null);
                setIsTransactionModalOpen(true);
            }}
            currentUser={currentUser}
            setActivePage={setActivePage}
            onSearch={setSearchQuery}
        >
             <button
              className="md:hidden mr-4 text-gray-500 focus:outline-none"
              onClick={() => setIsSidebarOpen(true)}
            >
              <MenuIcon className="h-6 w-6" />
            </button>
        </Header>

        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-slate-50 p-4 md:p-8 relative">
            {activePage === 'Dashboard' && (
                <Dashboard 
                    transactions={transactions} 
                    investments={investments}
                    setActivePage={setActivePage}
                    onEditTransaction={(t) => {
                        setEditingTransaction(t);
                        setIsTransactionModalOpen(true);
                    }}
                    onDeleteTransaction={handleDeleteTransaction}
                    onNewTransaction={() => {
                        setEditingTransaction(null);
                        setIsTransactionModalOpen(true);
                    }}
                    searchQuery={searchQuery}
                />
            )}
            {activePage === 'Transações' && (
                <Transactions 
                    transactions={transactions}
                    onOpenModal={(t) => {
                        setEditingTransaction(t);
                        setIsTransactionModalOpen(true);
                    }}
                    onDeleteTransaction={handleDeleteTransaction}
                    searchQuery={searchQuery}
                />
            )}
            {activePage === 'Agenda' && (
                <Agenda 
                    tasks={tasks}
                    onAddTask={handleAddTask}
                    onToggleTask={handleToggleTask}
                    onDeleteTask={handleDeleteTask}
                />
            )}
            {activePage === 'Investimentos' && (
                <Investments 
                    investments={investments}
                    setInvestments={setInvestments}
                    cdiRate={cdiRate}
                    onSaveInvestment={handleSaveInvestment}
                    onDeleteInvestment={handleDeleteInvestment}
                />
            )}
            {activePage === 'Configurações' && currentUser && (
                <Settings 
                    theme={theme} 
                    setTheme={setTheme}
                    currentUser={currentUser}
                    onUpdatePassword={handleUpdatePassword}
                    onUpdateAvatar={handleUpdateAvatar}
                    onCreateUser={handleCreateUser}
                />
            )}
        </main>
      </div>

      <TransactionModal
        isOpen={isTransactionModalOpen}
        onClose={() => setIsTransactionModalOpen(false)}
        onSave={handleSaveTransaction}
        transaction={editingTransaction}
      />

      {/* Floating WhatsApp Button */}
      <WhatsAppButton />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CalendarEvent } from '../types';
import { PlusIcon } from '../components/icons/PlusIcon';
import { TrashIcon } from '../components/icons/TrashIcon';
import { CheckCircleIcon } from '../components/icons/CheckCircleIcon';
import { XIcon } from '../components/icons/XIcon';
import { CalendarIcon } from '../components/icons/CalendarIcon';

interface AgendaProps {
    tasks: CalendarEvent[];
    onAddTask: (task: Omit<CalendarEvent, 'id'>) => void;
    onToggleTask: (id: string, done: boolean) => void;
    onDeleteTask: (id: string) => void;
}

const Agenda: React.FC<AgendaProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newTaskDesc, setNewTaskDesc] = useState('');
    const [newTaskDate, setNewTaskDate] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (newTaskDesc && newTaskDate) {
            onAddTask({
                description: newTaskDesc,
                date: newTaskDate,
                done: false
            });
            setNewTaskDesc('');
            setNewTaskDate('');
            setIsModalOpen(false);
        }
    };

    // Agrupar tarefas por data e ordenar cronologicamente
    const sortedTasks = [...tasks].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-3xl font-bold text-gray-800 flex items-center gap-2">
                    <CalendarIcon className="h-8 w-8 text-blue-600" />
                    Minha Agenda
                </h3>
                <button 
                    onClick={() => {
                        setNewTaskDate(new Date().toISOString().split('T')[0]);
                        setIsModalOpen(true);
                    }} 
                    className="flex items-center justify-center bg-blue-600 text-white px-5 py-2.5 rounded-full hover:bg-blue-700 transition-colors duration-200 text-sm font-bold shadow-md hover:shadow-lg"
                >
                    <PlusIcon className="h-5 w-5 mr-2" />
                    Adicionar Lembrete
                </button>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-xl border border-gray-200">
                {sortedTasks.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <CalendarIcon className="h-12 w-12 mx-auto text-gray-300 mb-3" />
                        <p className="text-lg font-medium">Sua agenda está vazia.</p>
                        <p className="text-sm mt-1 text-gray-400">Adicione lembretes para organizar seu dia.</p>
                    </div>
                ) : (
                    <ul className="space-y-4">
                        {sortedTasks.map((task) => {
                             const isPast = new Date(task.date) < new Date(new Date().setHours(0,0,0,0));
                             const isToday = new Date(task.date).toISOString().split('T')[0] === new Date().toISOString().split('T')[0];

                             return (
                                <li key={task.id} className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-300 group ${task.done ? 'bg-gray-50 border-gray-100' : 'bg-white border-gray-200 hover:border-blue-300 hover:shadow-md'}`}>
                                    <div className="flex items-center space-x-4 cursor-pointer flex-grow" onClick={() => onToggleTask(task.id, !task.done)}>
                                        <div 
                                            className={`p-2 rounded-full transition-all duration-300 ${task.done ? 'text-green-500 bg-green-50 scale-110' : 'text-gray-300 bg-gray-50 group-hover:text-blue-500 group-hover:bg-blue-50'}`}
                                        >
                                            <CheckCircleIcon className="h-6 w-6" />
                                        </div>
                                        <div>
                                            <p className={`font-bold text-lg transition-all duration-300 ${task.done ? 'line-through text-gray-400' : 'text-gray-800'}`}>
                                                {task.description}
                                            </p>
                                            <div className="flex items-center text-sm mt-1">
                                                <span className={`px-2 py-0.5 rounded text-xs font-semibold mr-2 ${
                                                    task.done ? 'bg-gray-100 text-gray-500' : 
                                                    isPast ? 'bg-red-100 text-red-700' : 
                                                    isToday ? 'bg-blue-100 text-blue-700' : 
                                                    'bg-indigo-50 text-indigo-600'
                                                }`}>
                                                    {task.done ? 'Concluído' : isPast ? 'Atrasado' : isToday ? 'Hoje' : 'Futuro'}
                                                </span>
                                                <span className={`${task.done ? 'text-gray-400' : 'text-gray-500'}`}>
                                                    {new Date(task.date).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <button 
                                        onClick={(e) => { 
                                            e.preventDefault();
                                            e.stopPropagation();
                                            e.nativeEvent.stopImmediatePropagation();
                                            onDeleteTask(task.id); 
                                        }}
                                        className="relative z-10 p-2 text-gray-300 hover:text-red-600 rounded-full hover:bg-red-50 transition-colors ml-4"
                                        title="Excluir"
                                    >
                                        <TrashIcon className="h-5 w-5" />
                                    </button>
                                </li>
                            );
                        })}
                    </ul>
                )}
            </div>

            {/* Modal de Adição */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-2xl w-full max-w-md m-4 p-6 animate-fade-in">
                        <div className="flex justify-between items-center mb-6 border-b pb-4">
                            <h3 className="text-xl font-bold text-gray-800">Novo Lembrete</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                                <XIcon className="h-6 w-6" />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-gray-700 mb-1">O que você precisa fazer?</label>
                                <input 
                                    type="text" 
                                    value={newTaskDesc}
                                    onChange={(e) => setNewTaskDesc(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
                                    placeholder="Ex: Pagar conta de luz"
                                    autoFocus
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-gray-700 mb-1">Quando?</label>
                                <input 
                                    type="date" 
                                    value={newTaskDate}
                                    onChange={(e) => setNewTaskDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
                                    required
                                />
                            </div>
                            <div className="flex justify-end pt-4 gap-2">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg font-medium transition-colors">
                                    Cancelar
                                </button>
                                <button type="submit" className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-blue-700 transition-colors shadow-lg hover:shadow-blue-500/30">
                                    Adicionar
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Agenda;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { SearchIcon } from './icons/SearchIcon';
import { BellIcon } from './icons/BellIcon';
import { PlusIcon } from './icons/PlusIcon';
import { User, CalendarEvent } from '../types';
import { Page } from '../types';
import { ClockIcon } from './icons/ClockIcon';
import { CalendarIcon } from './icons/CalendarIcon';


interface HeaderProps {
    children?: React.ReactNode;
    onLogout: () => void;
    onNewTransaction: () => void;
    currentUser: User | null;
    setActivePage: (page: Page) => void;
    onSearch: (query: string) => void;
    tasks: CalendarEvent[]; // Recebe as tarefas para gerar notificações
}

const Header: React.FC<HeaderProps> = ({ children, onLogout, onNewTransaction, currentUser, setActivePage, onSearch, tasks }) => {
  const [isProfileMenuOpen, setIsProfileMenuOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const profileMenuRef = useRef<HTMLDivElement>(null);
  const notificationsMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (profileMenuRef.current && !profileMenuRef.current.contains(event.target as Node)) {
        setIsProfileMenuOpen(false);
      }
      if (notificationsMenuRef.current && !notificationsMenuRef.current.contains(event.target as Node)) {
        setIsNotificationsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const handleViewProfile = () => {
      setActivePage('Configurações');
      setIsProfileMenuOpen(false);
  }

  // Lógica de Notificações: Tarefas não concluídas que são de HOJE ou ANTERIORES (Atrasadas)
  const notifications = useMemo(() => {
      const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

      const pending = tasks.filter(task => {
          if (task.done) return false;

          let taskDate = task.date;
          if (taskDate.includes('T')) taskDate = taskDate.split('T')[0];

          // Retorna verdadeiro se for hoje ou data passada (menor ou igual a hoje)
          return taskDate <= today;
      });

      // Ordena: Atrasadas primeiro, depois as de hoje
      return pending.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [tasks]);

  return (
    // Header Branco com sombra suave
    <header className="flex items-center justify-between px-6 py-4 bg-white shadow-sm border-b border-gray-200 z-10">
      <div className="flex items-center">
        {children}
        <div className="relative mx-4 lg:mx-0">
          <span className="absolute inset-y-0 left-0 flex items-center pl-3">
            <SearchIcon className="h-5 w-5 text-gray-400" />
          </span>
          <input
            className="w-32 sm:w-64 form-input pl-10 pr-4 rounded-full bg-gray-100 text-gray-700 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 border-transparent focus:border-transparent transition-all"
            type="text"
            placeholder="Buscar receitas, despesas..."
            onChange={(e) => onSearch(e.target.value)}
          />
        </div>
      </div>
      <div className="flex items-center">
         <button onClick={onNewTransaction} className="hidden sm:flex items-center justify-center bg-blue-600 text-white px-4 py-2 rounded-full hover:bg-blue-700 transition-colors duration-200 text-sm font-medium shadow-md hover:shadow-lg">
            <PlusIcon className="h-5 w-5 mr-2" />
            Nova Transação
        </button>

        <div className="relative mx-4" ref={notificationsMenuRef}>
            <button 
                onClick={() => setIsNotificationsOpen(!isNotificationsOpen)} 
                className="flex text-gray-500 hover:text-blue-600 transition-colors focus:outline-none relative"
            >
                <BellIcon className="h-6 w-6" />
                {notifications.length > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold text-white animate-pulse">
                        {notifications.length}
                    </span>
                )}
            </button>
            {isNotificationsOpen && (
                 <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl overflow-hidden z-20 border border-gray-200 animate-fade-in">
                    <div className="py-3 px-4 text-sm font-bold text-gray-800 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                        <span>Lembretes Pendentes</span>
                        <span className="bg-blue-100 text-blue-700 text-xs px-2 py-0.5 rounded-full">{notifications.length}</span>
                    </div>
                    <div className="divide-y divide-gray-100 max-h-80 overflow-y-auto">
                        {notifications.length === 0 ? (
                            <div className="p-6 text-center text-gray-500 text-sm">
                                <p>Tudo em dia! 🎉</p>
                                <p className="text-xs mt-1">Nenhuma tarefa pendente para hoje.</p>
                            </div>
                        ) : (
                            notifications.map((notif) => {
                                const today = new Date().toISOString().split('T')[0];
                                let notifDate = notif.date;
                                if(notifDate.includes('T')) notifDate = notifDate.split('T')[0];
                                const isLate = notifDate < today;

                                return (
                                    <div 
                                        key={notif.id} 
                                        onClick={() => {
                                            setActivePage('Agenda');
                                            setIsNotificationsOpen(false);
                                        }}
                                        className="flex items-start px-4 py-3 hover:bg-gray-50 cursor-pointer transition-colors"
                                    >
                                        {isLate ? (
                                            <ClockIcon className="h-5 w-5 text-red-500 mr-3 mt-0.5 flex-shrink-0" />
                                        ) : (
                                            <CalendarIcon className="h-5 w-5 text-blue-500 mr-3 mt-0.5 flex-shrink-0" />
                                        )}

                                        <div>
                                            <p className={`text-sm font-medium ${isLate ? 'text-red-600' : 'text-gray-800'}`}>
                                                {notif.description}
                                            </p>
                                            <p className="text-xs text-gray-500 mt-0.5">
                                                {isLate ? 'Atrasado - Era para ' : 'Para hoje - '}
                                                {new Date(notif.date).toLocaleDateString('pt-BR', { timeZone: 'UTC' })}
                                            </p>
                                        </div>
                                    </div>
                                );
                            })
                        )}
                    </div>
                    {notifications.length > 0 && (
                        <button 
                            onClick={() => {
                                setActivePage('Agenda');
                                setIsNotificationsOpen(false);
                            }}
                            className="w-full block text-center py-2 text-xs font-bold text-blue-600 hover:bg-blue-50 border-t border-gray-100 transition-colors"
                        >
                            Ver Agenda Completa
